const AWS = require('aws-sdk');
const s3 = new AWS.S3();

exports.handler = async (event) => {
    try {
        const bucket = event.Records[0].s3.bucket.name;
        const key = decodeURIComponent(event.Records[0].s3.object.key.replace(/\+/g, ' '));
        
        const params = {
            Bucket: bucket,
            Key: key
        };
        
        const data = await s3.getObject(params).promise();
        const fileContent = data.Body.toString('utf-8');
        
        // Process the file content (dummy processing)
        const processedContent = fileContent.toUpperCase(); // Example processing
        
        const outputBucket = 'your-output-bucket'; // Replace with your output bucket name
        const outputKey = key; // Use the original filename
        
        const uploadParams = {
            Bucket: outputBucket,
            Key: outputKey,
            Body: processedContent,
            ContentType: 'text/plain' // Adjust based on your file type
        };
        
        await s3.putObject(uploadParams).promise();
        
        return {
            statusCode: 200,
            body: JSON.stringify('File processed and uploaded successfully!')
        };
    } catch (error) {
        console.error(error);
        return {
            statusCode: 500,
            body: JSON.stringify('Error processing file.')
        };
    }
};